// Generate structured ESG report as HTML then convert to PDF
const items = $input.all();
const data = items[0].json;
const emailData = $('When Email with PDF Arrives').first().json;

const html = `
<!DOCTYPE html>
<html>
<head>
  <style>
    body { font-family: Arial, sans-serif; margin: 40px; }
    h1 { color: #2c5f2d; border-bottom: 3px solid #2c5f2d; }
    h2 { color: #4a7c59; margin-top: 30px; }
    .score-box { 
      background: #f0f8f0; 
      padding: 15px; 
      margin: 10px 0; 
      border-left: 4px solid #2c5f2d;
    }
    .metric { margin: 10px 0; }
    .label { font-weight: bold; color: #333; }
    .value { color: #2c5f2d; font-size: 1.2em; }
    table { width: 100%; border-collapse: collapse; margin: 20px 0; }
    th, td { padding: 12px; text-align: left; border-bottom: 1px solid #ddd; }
    th { background-color: #2c5f2d; color: white; }
  </style>
</head>
<body>
  <h1>ESG & Sustainability Analysis Report</h1>
  <p><strong>Generated:</strong> ${new Date().toLocaleDateString()}</p>
  <p><strong>Source:</strong> ${emailData.subject || 'Email Attachment'}</p>

  <h2>Overall ESG Score</h2>
  <div class="score-box">
    <div class="metric">
      <span class="label">Total ESG Score:</span>
      <span class="value">${data.esg_score}/100</span>
    </div>
  </div>

  <h2>Pillar Scores</h2>
  <table>
    <tr>
      <th>Pillar</th>
      <th>Score</th>
      <th>Rating</th>
    </tr>
    <tr>
      <td>Environmental</td>
      <td>${data.environmental_score}/100</td>
      <td>${data.environmental_score >= 70 ? 'Strong' : data.environmental_score >= 50 ? 'Moderate' : 'Needs Improvement'}</td>
    </tr>
    <tr>
      <td>Social</td>
      <td>${data.social_score}/100</td>
      <td>${data.social_score >= 70 ? 'Strong' : data.social_score >= 50 ? 'Moderate' : 'Needs Improvement'}</td>
    </tr>
    <tr>
      <td>Governance</td>
      <td>${data.governance_score}/100</td>
      <td>${data.governance_score >= 70 ? 'Strong' : data.governance_score >= 50 ? 'Moderate' : 'Needs Improvement'}</td>
    </tr>
  </table>

  <h2>Carbon Footprint Analysis</h2>
  <div class="score-box">
    <div class="metric">
      <span class="label">Total Carbon Footprint:</span>
      <span class="value">${data.carbon_footprint_tons.toLocaleString()} tons CO₂e</span>
    </div>
    ${data.carbon_intensity ? `
    <div class="metric">
      <span class="label">Carbon Intensity:</span>
      <span class="value">${data.carbon_intensity} tons CO₂e per unit</span>
    </div>
    ` : ''}
  </div>

  <h2>Sustainability Summary</h2>
  <p>${data.sustainability_summary}</p>

  ${data.key_risks ? `
  <h2>Key ESG Risks</h2>
  <p>${data.key_risks}</p>
  ` : ''}

  ${data.recommendations ? `
  <h2>Recommendations</h2>
  <p>${data.recommendations}</p>
  ` : ''}

  <hr style="margin-top: 40px;">
  <p style="font-size: 0.9em; color: #666;">
    This report was generated automatically using AI-powered ESG analysis.
  </p>
</body>
</html>
`;

// Convert HTML to PDF using a simple approach
// In production, you'd use a proper PDF library or service
const pdfBuffer = Buffer.from(html, 'utf-8');

return [{
  json: {
    reportGenerated: true,
    recipient: emailData.from,
    subject: 'ESG Analysis Report - ' + (emailData.subject || 'Your Document'),
    ...data
  },
  binary: {
    data: {
      data: pdfBuffer.toString('base64'),
      mimeType: 'text/html',
      fileName: 'ESG_Report_' + new Date().toISOString().split('T')[0] + '.html'
    }
  }
}];
